export default function SurgeryApp() {
  const [activeTopic, setActiveTopic] = useState<typeof topics[0] | null>(null);
  const [search, setSearch] = useState("");
  const [completed, setCompleted] = useState<Record<number, boolean>>({});
  
  const [aiQuery, setAiQuery] = useState("");
  const [aiResponse, setAiResponse] = useState("");
  const [isAiLoading, setIsAiLoading] = useState(false);

  const sidebarRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem("pediatrics_completed_full");
    if (saved) setCompleted(JSON.parse(saved));
  }, []);

  const toggleComplete = (id: number) => {
    const updated = { ...completed, [id]: !completed[id] };
    setCompleted(updated);
    localStorage.setItem("pediatrics_completed_full", JSON.stringify(updated));
  };

  const handleAiAsk = (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiQuery.trim()) return;

    setIsAiLoading(true);
    setAiResponse("");

    setTimeout(() => {
      const queryLower = aiQuery.toLowerCase();
      let foundAnswer = "";

      for (const key in aiKnowledgeBase) {
        if (queryLower.includes(key)) {
          foundAnswer = aiKnowledgeBase[key];
          break;
        }
      }

      if (foundAnswer) {
        setAiResponse(foundAnswer);
      } else {
        setAiResponse(
          `Запрос обработан. При подготовке ответа по теме "${activeTopic?.title}" всегда ориентируйтесь на утвержденные клинические протоколы МЗ РК. Попробуйте использовать ключевые медицинские термины: вакцина, стеноз, асфиксия, судороги, манту, патронаж.`
        );
      }
      setIsAiLoading(false);
    }, 600);
  };

  const filtered = topics.filter(
    t =>
      t.title.toLowerCase().includes(search.toLowerCase()) ||
      t.content.toLowerCase().includes(search.toLowerCase())
  );

  const openTopic = (topic: typeof topics[0]) => {
    setActiveTopic(topic);
    setAiQuery("");
    setAiResponse("");
    if (window.innerWidth <= 768 && sidebarRef.current) {
      sidebarRef.current.style.display = "none";
    }
  };

  const closeTopic = () => {
    setActiveTopic(null);
    if (window.innerWidth <= 768 && sidebarRef.current) {
      sidebarRef.current.style.display = "block";
    }
  };

  const renderContentText = (text: string) => {
    return text.split("\n").map((line, idx) => {
      const trimmed = line.trim();
      if (!trimmed) return <div key={idx} style={{ height: "10px" }} />;
      
      const parts = line.split(/(\*\*.*?\*\*)/g);
      return (
        <p key={idx} style={{ marginBottom: "8px", lineHeight: "1.6", color: "#333333", fontSize: "14px" }}>
          {parts.map((part, pIdx) => {
            if (part.startsWith("**") && part.endsWith("**")) {
              return <strong key={pIdx} style={{ color: "#4a148c", fontWeight: 600 }}>{part.slice(2, -2)}</strong>;
            }
            return part;
          })}
        </p>
      );
    });
  };

  return (
    <div style={{
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Arial, sans-serif',
      display: 'flex',
      height: '100vh',
      backgroundColor: '#f3e5f5',
      color: '#212121',
      overflow: 'hidden'
    }}>
      <style>{`
        ::-webkit-scrollbar { width: 6px; height: 6px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #ce93d8; border-radius: 4px; }
        ::-webkit-scrollbar-thumb:hover { background: #ab47bc; }
      `}</style>

      {/* ЛЕВАЯ ПАНЕЛЬ С БИЛЕТАМИ */}
      <div ref={sidebarRef} style={{
        width: '380px',
        borderRight: '1px solid #e1bee7',
        display: 'flex',
        flexDirection: 'column',
        backgroundColor: '#ffffff',
        flexShrink: 0
      }}>
        <div style={{ padding: '20px 20px 14px 20px', borderBottom: '1px solid #e1bee7' }}>
          <h1 style={{ fontSize: '18px', fontWeight: 700, color: '#4a148c', margin: 0, marginBottom: '2px' }}>
            Педиатрия: Полный курс
          </h1>
          <p style={{ fontSize: '11px', color: '#7b1fa2', margin: 0, fontWeight: 500 }}>
            Тенажер экзамена • 70 Билетов + 21 Навык
          </p>
          
          <input
            type="text"
            placeholder="Поиск по теме или тексту..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            style={{
              width: '100%',
              padding: '9px 12px',
              marginTop: '12px',
              borderRadius: '8px',
              border: '1px solid #ce93d8',
              backgroundColor: '#fafafa',
              fontSize: '13px',
              color: '#212121',
              outline: 'none',
              boxSizing: 'border-box'
            }}
          />
        </div>

        <div style={{ flex: 1, overflowY: 'auto', padding: '10px' }}>
          <div style={{ display: 'grid', gap: '6px' }}>
            {filtered.map(t => (
              <div key={t.id} onClick={() => openTopic(t)}
                style={{
                  background: activeTopic?.id === t.id ? '#f3e5f5' : '#ffffff',
                  border: activeTopic?.id === t.id ? '1px solid #8e24aa' : '1px solid #f8f0fa',
                  borderRadius: '10px',
                  padding: '10px 12px',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '10px',
                  transition: 'all 0.1s'
                }}>
                <div style={{
                  width: '28px',
                  height: '28px',
                  borderRadius: '6px',
                  background: completed[t.id] ? '#4a148c' : '#f3e5f5',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '11px',
                  fontWeight: 600,
                  color: completed[t.id] ? '#ffffff' : '#7b1fa2',
                  flexShrink: 0
                }}>
                  {completed[t.id] ? '✓' : t.id}
                </div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontSize: '13px', color: '#212121', fontWeight: completed[t.id] ? 600 : 400, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                    {t.title}
                  </div>
                  <div style={{ fontSize: '11px', color: '#8e24aa', marginTop: '1px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                    {t.short}
                  </div>
                </div>
              </div>
            ))}
            {filtered.length === 0 && (
              <div style={{ textAlign: 'center', color: '#757575', marginTop: '20px', fontSize: '13px' }}>Ничего не найдено</div>
            )}
          </div>
        </div>
      </div>

      {/* ЦЕНТРАЛЬНАЯ ПАНЕЛЬ ИЗУЧЕНИЯ БИЛЕТА */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', backgroundColor: '#fafafa' }}>
        {activeTopic ? (
          <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
            <div style={{
              padding: '14px 20px',
              borderBottom: '1px solid #e1bee7',
              backgroundColor: '#ffffff',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              gap: '12px'
            }}>
              <button onClick={closeTopic} style={{
                background: 'none', border: 'none', color: '#7b1fa2', cursor: 'pointer', fontSize: '14px', fontWeight: 500
              }}>
                ← К списку
              </button>
              
              <div style={{ flex: 1, minWidth: 0, marginLeft: '8px' }}>
                <h2 style={{ fontSize: '15px', fontWeight: 600, color: '#4a148c', margin: 0, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                  {activeTopic.title}
                </h2>
              </div>

              <button onClick={() => toggleComplete(activeTopic.id)} style={{
                backgroundColor: completed[activeTopic.id] ? '#7b1fa2' : 'transparent',
                border: '1px solid #7b1fa2',
                color: completed[activeTopic.id] ? '#ffffff' : '#7b1fa2',
                borderRadius: '16px',
                padding: '5px 12px',
                fontSize: '12px',
                fontWeight: 500,
                cursor: 'pointer'
              }}>
                {completed[activeTopic.id] ? 'Освоено ✓' : 'Отметить готовым'}
              </button>
            </div>

            <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
              <div style={{ flex: 1, overflowY: 'auto', padding: '24px 30px', backgroundColor: '#ffffff' }}>
                <div style={{ maxWidth: '750px', margin: '0 auto' }}>
                  {renderContentText(activeTopic.content)}
                </div>
              </div>

              <div style={{
                width: '300px',
                borderLeft: '1px solid #e1bee7',
                backgroundColor: '#fdfbfe',
                display: 'flex',
                flexDirection: 'column',
                flexShrink: 0
              }}>
                <div style={{ padding: '14px', borderBottom: '1px solid #f3e5f5', backgroundColor: '#f3e5f5' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                    <span style={{ fontSize: '16px' }}>🧠</span>
                    <div>
                      <div style={{ fontSize: '13px', fontWeight: 600, color: '#4a148c' }}>ИИ-Помощник</div>
                      <div style={{ fontSize: '10px', color: '#7b1fa2' }}>Справка по протоколам МЗ РК</div>
                    </div>
                  </div>
                </div>

                <div style={{ flex: 1, padding: '14px', overflowY: 'auto', fontSize: '12px' }}>
                  {aiResponse ? (
                    <div style={{
                      backgroundColor: '#ffffff',
                      border: '1px solid #e1bee7',
                      borderRadius: '8px',
                      padding: '10px',
                      lineHeight: '1.4',
                      color: '#424242'
                    }}>
                      <div style={{ fontWeight: 600, color: '#7b1fa2', marginBottom: '4px', fontSize: '10px', textTransform: 'uppercase' }}>
                        Подсказка ИИ:
                      </div>
                      {aiResponse}
                    </div>
                  ) : (
                    <div style={{ textAlign: 'center', color: '#9e9e9e', marginTop: '30px' }}>
                      {isAiLoading ? (
                        <div style={{ color: '#8e24aa' }}>Поиск по базе знаний...</div>
                      ) : (
                        "Введите ключевое слово темы (напр. вакцина, стеноз, манту, судороги) для получения клинической справки."
                      )}
                    </div>
                  )}
                </div>

                <form onSubmit={handleAiAsk} style={{ padding: '10px', borderTop: '1px solid #e1bee7', backgroundColor: '#ffffff' }}>
                  <div style={{ display: 'flex', gap: '4px' }}>
                    <input
                      type="text"
                      placeholder="Ключевое слово..."
                      value={aiQuery}
                      onChange={e => setAiQuery(e.target.value)}
                      disabled={isAiLoading}
                      style={{
                        flex: 1,
                        padding: '7px 10px',
                        borderRadius: '6px',
                        border: '1px solid #ce93d8',
                        fontSize: '12px',
                        outline: 'none'
                      }}
                    />
                    <button
                      type="submit"
                      disabled={isAiLoading}
                      style={{
                        backgroundColor: '#7b1fa2',
                        color: '#ffffff',
                        border: 'none',
                        borderRadius: '6px',
                        padding: '0 10px',
                        fontSize: '12px',
                        cursor: 'pointer'
                      }}
                    >
                      ОК
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        ) : (
          <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', color: '#7b1fa2' }}>
            <span style={{ fontSize: '40px', marginBottom: '12px' }}>🩺</span>
            <div style={{ fontSize: '15px', fontWeight: 500 }}>Выберите билет для подготовки</div>
            <div style={{ fontSize: '11px', color: '#9c27b0', marginTop: '2px' }}>Загружена вся база данных: 91 активная тема</div>
          </div>
        )}
      </div>
    </div>
  );
}
